import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Trash2, Upload, PencilLine, Save, Plus } from 'lucide-react';
import toast from 'react-hot-toast';

const Admin = () => {
  const [products, setProducts] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    price: '',
    category: 'Gifts',
    description: ''
  });
  const [images, setImages] = useState([]);
  const [removedImages, setRemovedImages] = useState([]);
  const [imagePreviews, setImagePreviews] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchProducts();
  }, []);

  useEffect(() => {
    const previewUrls = images.map((file) => URL.createObjectURL(file));
    setImagePreviews(previewUrls);

    return () => {
      previewUrls.forEach((url) => URL.revokeObjectURL(url));
    };
  }, [images]);

  const fetchProducts = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/products');
      setProducts(response.data);
    } catch (error) {
      console.error('Error fetching products:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const isEditing = Boolean(selectedProduct);
    const currentGallery = Array.isArray(selectedProduct?.images) && selectedProduct.images.length > 0
      ? selectedProduct.images
      : selectedProduct?.image
        ? [selectedProduct.image]
        : [];
    const remainingExistingImages = currentGallery.filter((img) => !removedImages.includes(img));

    if (!isEditing && images.length === 0) {
      toast.error('Please select at least one image');
      return;
    }

    setLoading(true);
    const formDataToSend = new FormData();
    formDataToSend.append('name', formData.name);
    formDataToSend.append('price', formData.price);
    formDataToSend.append('category', formData.category);
    formDataToSend.append('description', formData.description);
    images.forEach((file) => {
      formDataToSend.append('images', file);
    });
    if (isEditing) {
      formDataToSend.append('removedImages', JSON.stringify(removedImages));
    }

    if (isEditing && images.length === 0 && remainingExistingImages.length === 0) {
      toast.error('Please keep at least one image or add a new one');
      setLoading(false);
      return;
    }

    try {
      if (isEditing) {
        await axios.put(`http://localhost:5000/api/products/${selectedProduct._id}`, formDataToSend, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Product updated successfully!');
      } else {
        await axios.post('http://localhost:5000/api/products', formDataToSend, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        toast.success('Product added successfully!');
      }
      setFormData({ name: '', price: '', category: 'Gifts', description: '' });
      setImages([]);
      setRemovedImages([]);
      setSelectedProduct(null);
      fetchProducts();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save product');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (productId) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      try {
        await axios.delete(`http://localhost:5000/api/products/${productId}`);
        toast.success('Product deleted');
        if (selectedProduct?._id === productId) {
          setSelectedProduct(null);
        }
        fetchProducts();
      } catch (error) {
        toast.error('Failed to delete product');
      }
    }
  };

  const startEdit = (product) => {
    setSelectedProduct(product);
    setFormData({
      name: product.name,
      price: product.price,
      category: product.category,
      description: product.description || ''
    });
    setImages([]);
    setRemovedImages([]);
  };

  const resetForm = () => {
    setSelectedProduct(null);
    setFormData({ name: '', price: '', category: 'Gifts', description: '' });
    setImages([]);
    setRemovedImages([]);
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="admin-header mb-8">
        <div>
          <p className="text-sm uppercase tracking-[0.3em] text-rose-600">Control center</p>
          <h1 className="text-3xl font-bold text-slate-800 mt-2">Admin Dashboard</h1>
        </div>
        <button onClick={resetForm} className="btn-secondary">
          <Plus size={16} className="inline mr-2" />
          New item
        </button>
      </div>
      
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="dashboard-panel">
          <h2 className="panel-title">{selectedProduct ? 'Edit Product' : 'Add New Product'}</h2>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Product Name</label>
              <input
                type="text"
                name="name"
                required
                className="input-field"
                value={formData.name}
                onChange={handleChange}
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Price (â‚¬)</label>
              <input
                type="number"
                name="price"
                required
                step="0.01"
                className="input-field"
                value={formData.price}
                onChange={handleChange}
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Category</label>
              <select
                name="category"
                className="input-field"
                value={formData.category}
                onChange={handleChange}
              >
                <option value="Gifts">Gifts</option>
                <option value="Keychains">Keychains</option>
                <option value="Decorations">Decorations</option>
                <option value="Accessories">Accessories</option>
                <option value="Apparel">Apparel</option>
              </select>
            </div>
            
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Description (optional)</label>
              <textarea
                name="description"
                rows="3"
                className="input-field"
                value={formData.description}
                onChange={handleChange}
              />
            </div>
            
            <div>
              {selectedProduct && (
                <>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Current Gallery</label>
                  <div className="mb-3 flex flex-wrap gap-3">
                    {(
                      (Array.isArray(selectedProduct.images) && selectedProduct.images.length > 0
                        ? selectedProduct.images
                        : selectedProduct.image
                          ? [selectedProduct.image]
                          : [])
                    )
                      .filter((img) => !removedImages.includes(img))
                      .map((img, index) => (
                        <div key={img + index} className="relative h-16 w-16 rounded-xl overflow-hidden border border-rose-100 bg-white">
                          <img
                            src={`http://localhost:5000${img}`}
                            alt={`Existing ${index + 1}`}
                            className="h-full w-full object-cover"
                          />
                          <button
                            type="button"
                            onClick={() => setRemovedImages((prev) => [...prev, img])}
                            className="absolute top-0 right-0 h-5 w-5 bg-red-500 text-white text-xs leading-none rounded-bl-md"
                            title="Remove image"
                          >
                            Ă—
                          </button>
                        </div>
                      ))}
                    {(
                      (Array.isArray(selectedProduct.images) && selectedProduct.images.length > 0
                        ? selectedProduct.images
                        : selectedProduct.image
                          ? [selectedProduct.image]
                          : [])
                    ).filter((img) => !removedImages.includes(img)).length === 0 && (
                      <p className="text-xs text-slate-700">No existing images left. Add new images before saving.</p>
                    )}
                  </div>
                </>
              )}

              <label className="block text-sm font-medium text-slate-700 mb-1">Product Images {selectedProduct ? '(new uploads will be added to the current gallery)' : ''}</label>
              <input
                type="file"
                accept="image/*"
                multiple
                onChange={(e) => setImages(Array.from(e.target.files || []))}
                className="w-full text-slate-700"
                required={!selectedProduct}
              />
              <p className="mt-2 text-xs text-slate-700">Upload several photos so shoppers can inspect the item from different angles.</p>
              {imagePreviews.length > 0 && (
                <div className="mt-3 flex flex-wrap gap-3">
                  {imagePreviews.map((preview, index) => (
                    <div key={preview} className="h-16 w-16 rounded-xl overflow-hidden border border-rose-100 bg-white">
                      <img
                        src={preview}
                        alt={`Selected preview ${index + 1}`}
                        className="h-full w-full object-cover"
                      />
                    </div>
                  ))}
                </div>
              )}
            </div>
            
            <button
              type="submit"
              disabled={loading}
              className="btn-primary w-full flex items-center justify-center gap-2"
            >
              {selectedProduct ? <Save size={18} /> : <Upload size={18} />}
              {loading ? 'Saving...' : selectedProduct ? 'Save Changes' : 'Add Product'}
            </button>
          </form>
        </div>
        
        <div className="dashboard-panel">
          <h2 className="panel-title">Manage Products</h2>
          <p className="panel-subtitle">Select any item to edit it instantly.</p>
          <div className="space-y-3 max-h-[32rem] overflow-y-auto pr-1">
            {products.map(product => (
              <div key={product._id} className={`flex items-center gap-4 p-3 border rounded-2xl ${selectedProduct?._id === product._id ? 'border-amber-300 bg-amber-50/20' : 'border-white/10 bg-white/5'}`}>
                <img
                  src={`http://localhost:5000${product.images?.[0] || product.image}`}
                  alt={product.name}
                  className="w-16 h-16 object-cover rounded"
                />
                <div className="flex-1">
                  <h3 className="font-semibold text-slate-800">{product.name}</h3>
                  <p className="text-sm text-slate-700">â‚¬{product.price}</p>
                  <p className="text-xs text-rose-600">{product.category} â€˘ {product.images?.length || 1} photo{(product.images?.length || 1) > 1 ? 's' : ''}</p>
                </div>
                <button
                  onClick={() => startEdit(product)}
                  className="text-rose-400 hover:text-rose-500 transition"
                >
                  <PencilLine size={18} />
                </button>
                <button
                  onClick={() => handleDelete(product._id)}
                  className="text-sky-400 hover:text-sky-500 transition"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            ))}
            {products.length === 0 && (
              <p className="text-slate-700 text-center py-4">No products yet. Add your first product!</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Admin;
